sp_widget.client_script:
function($filter,spUtil,cabrillo,$rootScope, i18n) {
	/* widget controller */
	var c = this;
	c.isNative = cabrillo.isNative();

	//Use KB specific stylic for "kb" & 'mesp' portal
	c.KBRatingStyle = c.options.kb_rating_style || ($rootScope.portal ? ($rootScope.portal.sys_id == "45d6680fdb52220099f93691f0b8f5ad" || $rootScope.portal.sys_id == "26f2fffb77322300454792718a1061e5") : false);

	c.getOrderedItems = function() {
		var filtered = $filter('limitTo') (c.options.result, c.options.max_records);
		return $filter('orderBy') (filtered, 'count', c.options.reverse);
	}
}

sp_widget.css:
/*This was sdded so Artcile widet and the related article widget would align size and text */
.dtech-kb-align{
  margin-top:6px;
  min-height: 41px;
}
.kb-list-item{
  border-bottom: none;
  border-top: none; 
}
small{
  font-size:93%; 
}
.secondary-info{
  color:$text-muted;
  padding-top: 3px;
}
.main_text a{
  display:block; 
}
.dot{
  padding:5px; 
}
.kb-star-on {
  text-shadow: $fav-star-outline;
}
.kb-star-off {
  color: $fav-star-color-off !important;
  text-shadow: $fav-star-outline;
}
.sp-stars{
  display: inline-flex;
  letter-spacing: .5px;
}
.kb-rating-stars{
  font-size: 12px;
  display: inline-flex;
  margin-top: -6px;

  .glyphicon{
    line-height: 0; 
  }
  .rating-stars [role="button"] {
    cursor: text;
  }
}
.kb-mobile{
  .kb-mobile-panel{
    .panel-heading{
      padding-left:0px !important;
      .panel-title{
        font-size:20px !important; 
      }
    }
    .kb-item-block{
      box-shadow:1px 1px 10px 0.2px rgba(0,0,0,0.1);
      padding:15px;
      margin-bottom:10px;
      margin-top: 15px;
      border-radius: 7px;
    }
  }
}
.kb-list-block.has-icon {
  .kb-list-item {
    .kb-list-row {
      overflow: hidden;
      clear: both;
    }
    .kb-list-col-icon {
      float: left;
      width : 30px;
      padding-top: 3px;
      .fa {
        width: 30px;
        font-size: 20px;
        vertical-align: middle;
        color: $brand-primary;
        float: left;
      }
    }
    .kb-list-col-content {
      float: left;
      width: calc(100% - 30px);
    }
  }
}
.kb-rating-stars [role="slider"]:focus{
   box-shadow:none !important;
   outline:none !important;
   border:none !important;
}

sp_widget.link:
function(scope) {	
	var c = scope.c;

	c.openArticleAttachment = function(url, name,  external) {
		if(external) {
			var params = 'toolbar=no,menubar=no,personalbar=no,height='+screen.height + ',' + 'width='+screen.width + ',' + 'scrollbars=yes,resizable=yes,fullscreen=yes';
			window.open(url, name, params);
		}
		else
			window.open(url, name, "toolbar=no,menubar=no,personalbar=no,width=800,height=600,scrollbars=yes,resizable=yes");
	};

	c.roundOff = function(val){
		if(val)
			return Math.round(val);
		else
			return 0;
	};
}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2021 Discover Technologies LLC
/* Special License Rights
 *  The Government's rights to use, display, or disclose this software are restricted.
